phase1.code:
// ---- Base class (must be open) ----
open class Animal(
    open val name: String,
    open val age: Int
) {
    // Must be open to be overridden
    open fun speak() {
        println("$name makes a sound")
    }

    fun eat() {
        println("$name is eating")
    }
}

// ---- Derived class ----
class Dog(
    override val name: String,
    override val age: Int,
    val breed: String
) : Animal(name, age) {
    override fun speak() {
        println("$name says: Woof! Woof!")
    }

    fun fetch() {
        println("$name is fetching the ball")
    }
}

// ---- Derived class with additional properties ----
class Cat(
    override val name: String,
    override val age: Int,
    val color: String
) : Animal(name, age) {
    override fun speak() {
        println("$name says: Meow!")
    }

    fun purr() {
        println("$name is purring")
    }
}

// ---- Abstract class ----
abstract class Shape {
    abstract fun area(): Double
    abstract fun perimeter(): Double

    fun info() {
        println("Area: ${area()}, Perimeter: ${perimeter()}")
    }
}

class Circle(
    private val radius: Double
) : Shape() {
    override fun area(): Double = Math.PI * radius * radius
    override fun perimeter(): Double = 2 * Math.PI * radius
}

class Rectangle(
    private val width: Double,
    private val height: Double
) : Shape() {
    override fun area(): Double = width * height
    override fun perimeter(): Double = 2 * (width + height)
}

// ---- Inheritance with init block ----
open class Parent(val name: String) {
    init {
        println("Parent init: $name")
    }
}

class Child(name: String, val age: Int) : Parent(name) {
    init {
        println("Child init: $name, $age")
    }
}

fun main() {
    // ---- Using inheritance ----
    val dog = Dog("Max", 3, "Labrador")
    val cat = Cat("Whiskers", 2, "Orange")

    dog.speak()
    dog.eat()
    dog.fetch()

    cat.speak()
    cat.eat()
    cat.purr()

    // ---- Polymorphism ----
    val animals: List<Animal> = listOf(dog, cat)
    for (animal in animals) {
        animal.speak()
        // animal.fetch() won't work here
        // animal.purr() won't work here
    }

    // ---- Abstract classes ----
    val circle = Circle(5.0)
    val rectangle = Rectangle(4.0, 6.0)

    circle.info()
    rectangle.info()

    // ---- Init block order ----
    val child = Child("Alice", 10)
}

phase2.brokenCode:
fun main() {
    // Trying to inherit from a non-open class
    class Animal(val name: String)
    class Dog(name: String) : Animal(name)  // Error!

    // Trying to override a non-open method
    open class Animal2 {
        fun speak() { println("Hello") }  // Not open
    }
    class Dog2 : Animal2() {
        override fun speak() { println("Woof") }  // Error!
    }

    // Trying to instantiate an abstract class
    abstract class Shape
    val shape = Shape()  // Error!
}

phase2.explanation:
🤖 **You must explicitly mark things as open for inheritance.**

**The problems:**

1. **Class not open:**
```kotlin
class Animal(val name: String)
class Dog(name: String) : Animal(name)  // ❌ Animal is final
```

2. **Method not open:**
```kotlin
open class Animal {
    fun speak() { }  // ❌ Not open
}
class Dog : Animal() {
    override fun speak() { }  // ❌ Cannot override
}
```

3. **Abstract class instantiation:**
```kotlin
abstract class Shape
val shape = Shape()  // ❌ Cannot instantiate abstract
```

**The fixes:**
```kotlin
// Fix 1:
open class Animal(val name: String)
class Dog(name: String) : Animal(name)

// Fix 2:
open class Animal {
    open fun speak() { }
}
class Dog : Animal() {
    override fun speak() { }
}

// Fix 3:
val shape = object : Shape() { }  // Anonymous object
```

**Kotlin-chan says:**
"Kotlin makes you think about inheritance. It's intentional."

**Rules:**
1. Class must be `open` to inherit
2. Method must be `open` to override
3. Abstract classes can't be instantiated

phase3.solution:
open class Vehicle(
    val brand: String,
    val model: String
) {
    open fun start() {
        println("$brand $model is starting")
    }
}

class Car(
    brand: String,
    model: String,
    val doors: Int
) : Vehicle(brand, model) {
    override fun start() {
        super.start()
        println("Car with $doors doors")
    }
}

class Motorcycle(
    brand: String,
    model: String,
    val hasSidecar: Boolean
) : Vehicle(brand, model) {
    override fun start() {
        super.start()
        println("Motorcycle sidecar: $hasSidecar")
    }
}

fun main() {
    val car = Car("Toyota", "Corolla", 4)
    car.start()

    val bike = Motorcycle("Harley", "Sportster", false)
    bike.start()
}
